const fontMap=(ff)=>{if(!ff)return"Calibri";const m={"'Outfit',sans-serif":"Calibri","'Inter',sans-serif":"Calibri","'Roboto',sans-serif":"Arial","'Poppins',sans-serif":"Calibri","'Montserrat',sans-serif":"Calibri","'Playfair Display',serif":"Georgia","'Lora',serif":"Georgia","'Merriweather',serif":"Georgia","'Space Grotesk',sans-serif":"Calibri","'DM Sans',sans-serif":"Calibri","'Raleway',sans-serif":"Calibri","'Nunito',sans-serif":"Calibri","'Oswald',sans-serif":"Arial Narrow","'Bebas Neue',sans-serif":"Impact","'Fira Code',monospace":"Courier New","'JetBrains Mono',monospace":"Courier New","'Caveat',cursive":"Comic Sans MS","'Dancing Script',cursive":"Comic Sans MS","'Pacifico',cursive":"Comic Sans MS","'Permanent Marker',cursive":"Impact"};return m[ff]||"Calibri"};
